# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Blueprint, request, jsonify, g
from functools import wraps
from datetime import datetime

users_bp = Blueprint('users', __name__)

# Mock database - replace with actual database in production
users_db = {}
next_user_id = 1

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        current_user = getattr(g, 'current_user', None)
        if not current_user or current_user.get('role') != 'admin':
            return jsonify({'error': 'Unauthorized. Admin access required.'}), 403
        return f(*args, **kwargs)
    return decorated_function

@users_bp.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    current_user = g.current_user
    
    if user_id not in users_db:
        return jsonify({'error': 'User not found'}), 404
    
    user = users_db[user_id]
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    allowed_fields = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    valid_roles = ['user', 'moderator', 'admin']
    valid_statuses = ['active', 'suspended']
    valid_tiers = ['free', 'pro', 'enterprise']
    
    updates = {}
    errors = []
    
    for field in data:
        if field not in allowed_fields:
            errors.append(f'Field "{field}" is not allowed to be updated')
            continue
        
        value = data[field]
        
        if field == 'email':
            if not value or '@' not in value:
                errors.append('Invalid email format')
                continue
            if any(u.get('email') == value and uid != user_id for uid, u in users_db.items()):
                errors.append('Email already exists')
                continue
            updates['email'] = value
        
        elif field == 'username':
            if not value or len(value) < 3:
                errors.append('Username must be at least 3 characters')
                continue
            if any(u.get('username') == value and uid != user_id for uid, u in users_db.items()):
                errors.append('Username already exists')
                continue
            updates['username'] = value
        
        elif field == 'role':
            if value not in valid_roles:
                errors.append(f'Invalid role. Must be one of: {", ".join(valid_roles)}')
                continue
            if user_id == current_user['id'] and value != current_user['role']:
                errors.append('Cannot change your own role')
                continue
            updates['role'] = value
        
        elif field == 'account_status':
            if value not in valid_statuses:
                errors.append(f'Invalid account status. Must be one of: {", ".join(valid_statuses)}')
                continue
            if user_id == current_user['id'] and value == 'suspended':
                errors.append('Cannot suspend your own account')
                continue
            updates['account_status'] = value
        
        elif field == 'subscription_tier':
            if value not in valid_tiers:
                errors.append(f'Invalid subscription tier. Must be one of: {", ".join(valid_tiers)}')
                continue
            updates['subscription_tier'] = value
    
    if errors:
        return jsonify({'error': 'Validation failed', 'details': errors}), 400
    
    if not updates:
        return jsonify({'error': 'No valid fields to update'}), 400
    
    for key, value in updates.items():
        user[key] = value
    
    user['updated_at'] = datetime.utcnow().isoformat()
    user['updated_by'] = current_user['id']
    
    response_user = {k: v for k, v in user.items() if k != 'password'}
    
    return jsonify({
        'message': 'User updated successfully',
        'user': response_user
    }), 200

def create_user(username, email, role='user', account_status='active', subscription_tier='free'):
    global next_user_id
    user_id = next_user_id
    next_user_id += 1
    
    users_db[user_id] = {
        'id': user_id,
        'username': username,
        'email': email,
        'role': role,
        'account_status': account_status,
        'subscription_tier': subscription_tier,
        'created_at': datetime.utcnow().isoformat(),
        'updated_at': datetime.utcnow().isoformat()
    }
    
    return users_db[user_id]